     6→use Illuminate\Database\Eloquent\Relations\BelongsTo;
     7→use Illuminate\Database\Eloquent\Relations\HasMany;
     8→
     9→class Project extends Model
    10→{
    11→    protected $fillable = ['user_id', 'name', 'description', 'deadline', 'status'];
    12→
    13→    protected $casts = [
    14→        'deadline' => 'date',
    15→    ];
    16→
    17→    public function user(): BelongsTo
    18→    {
    19→        return $this->belongsTo(User::class);
    20→    }
    21→
    22→    public function tasks(): HasMany
    23→    {
    24→        return $this->hasMany(Task::class);
    25→    }
    26→
    27→    public function tags(): HasMany
    28→    {
    29→        return $this->hasMany(Tag::class);
    30→    }
    31→
    32→    public function completionPercentage(): int
    33→    {
    34→        $total = $this->tasks()->count();
    35→        if ($total === 0) return 0;
    36→        $done = $this->tasks()->where('status', 'done')->count();
    37→        return (int) round(($done / $total) * 100);
    38→    }
    39→}
