    13→        $projects = $request->user()
    14→            ->projects()
    15→            ->where('status', $status)
    16→            ->withCount('tasks')
    17→            ->with('tasks')
    18→            ->latest()
    19→            ->get();
    20→
    21→        return view('projects.index', compact('projects', 'status'));
    22→    }
    23→
    24→    public function store(Request $request)
    25→    {
    26→        $validated = $request->validate([
    27→            'name' => 'required|string|max:255',
    28→            'description' => 'nullable|string',
    29→            'deadline' => 'nullable|date',
    30→        ]);
    31→
    32→        $request->user()->projects()->create($validated);
    33→
    34→        return redirect()->route('projects.index')->with('success', 'Proyecto creado.');
    35→    }
    36→
    37→    public function show(Request $request, Project $project)
    38→    {
    39→        $this->authorize('view', $project);
    40→
    41→        $project->load(['tasks.subtasks', 'tasks.tags', 'tags']);
    42→
    43→        $columns = [
    44→            'backlog'     => $project->tasks->where('status', 'backlog')->sortBy('position')->values(),
    45→            'in_progress' => $project->tasks->where('status', 'in_progress')->sortBy('position')->values(),
    46→            'testing'     => $project->tasks->where('status', 'testing')->sortBy('position')->values(),
    47→            'done'        => $project->tasks->where('status', 'done')->sortBy('position')->values(),
    48→        ];
    49→
    50→        $projectTags = $project->tags;
    51→
    52→        return view('projects.show', compact('project', 'columns', 'projectTags'));
    53→    }
    54→
    55→    public function update(Request $request, Project $project)
    56→    {
    57→        $this->authorize('update', $project);
    58→
    59→        $validated = $request->validate([
    60→            'name' => 'required|string|max:255',
    61→            'description' => 'nullable|string',
    62→            'deadline' => 'nullable|date',
    63→            'status' => 'required|in:active,archived',
    64→        ]);
    65→
    66→        $project->update($validated);
    67→
    68→        return redirect()->route('projects.show', $project)->with('success', 'Proyecto actualizado.');
    69→    }
    70→
